   101→export function generateOptimizedRobots(config: RobotsConfig): string {
   102→  const url = normalizeUrl(config.url);
   103→  const blockedPaths = config.blockedPaths?.length ? config.blockedPaths : ['/admin', '/login', '/cart'];
   104→
   105→  return `# Robots.txt optimise pour l indexation IA (CitedBy.ai)
   106→# Generated: ${new Date().toISOString().split('T')[0]}
   107→
   108→User-agent: *
   109→${blockedPaths.map(path => `Disallow: ${path}`).join('\n')}
   110→Allow: /
   111→
   112→# --- AI BOTS ---
   113→${AI_BOTS.map(bot => `User-agent: ${bot.userAgent}\nAllow: /\n`).join('\n')}
   114→Sitemap: ${url.replace(/\/$/, '')}/sitemap.xml
   115→`;
   116→}
   117→
   118→export function checkBotAccess(robotsTxt: string, botUserAgent: string): 'allowed' | 'blocked' | 'default' {
   119→  const lines = robotsTxt.split('\n').map(line => line.trim());
   120→  let activeAgents: string[] = [];
   121→  let allowRules: string[] = [];
   122→  let disallowRules: string[] = [];
   123→  const rulesByAgent: Record<string, { allow: string[]; disallow: string[] }> = {};
   124→
   125→  for (const line of lines) {
   126→    if (!line || line.startsWith('#')) continue;
   127→    const [rawKey, rawValue] = line.split(':');
   128→    if (!rawKey || !rawValue) continue;
   129→    const key = rawKey.trim().toLowerCase();
   130→    const value = rawValue.trim();
   131→
   132→    if (key === 'user-agent') {
   133→      activeAgents = [value];
   134→      if (!rulesByAgent[value]) rulesByAgent[value] = { allow: [], disallow: [] };
   135→      allowRules = rulesByAgent[value].allow;
   136→      disallowRules = rulesByAgent[value].disallow;
   137→    }
   138→
   139→    if (key === 'allow') allowRules.push(value);
   140→    if (key === 'disallow') disallowRules.push(value);
   141→  }
   142→
   143→  const agentRules = rulesByAgent[botUserAgent] || rulesByAgent['*'];
   144→  if (!agentRules) return 'default';
   145→  if (agentRules.disallow.includes('/')) return 'blocked';
   146→  if (agentRules.allow.includes('/') || agentRules.disallow.length === 0) return 'allowed';
   147→  return 'default';
   148→}
