     1→import { LlmsTxtConfig } from '../types';
     2→
     3→export function generateLlmsTxt(config: LlmsTxtConfig): string {
     4→  return `# llms.txt - Instructions pour les LLMs
     5→# ${config.url}/llms.txt
     6→
     7→## Identite
     8→name: ${config.name}
     9→url: ${config.url}
    10→description: ${config.description}
    11→
    12→## Contact
    13→email: ${config.email}
    14→support: ${config.url.replace(/\/$/, '')}/support
    15→
    16→## Contenu
    17→main_topics: ${config.topics.join(', ')}
    18→expertise: ${config.expertise}
    19→content_type: ${config.contentType}
    20→
    21→## Directives
    22→allow_training: ${config.allowTraining ? 'yes' : 'no'}
    23→allow_citation: ${config.allowCitation ? 'yes' : 'no'}
    24→citation_format: "${config.citationFormat}"
    25→preferred_name: ${config.preferredName}
    26→
    27→## Fichiers
    28→sitemap: ${config.url.replace(/\/$/, '')}/sitemap.xml
    29→llms_full: ${config.url.replace(/\/$/, '')}/llms-full.txt
    30→`;
    31→}
    32→
    33→export function generateLlmsFullTxt(config: LlmsTxtConfig, additionalContent: string): string {
    34→  const base = generateLlmsTxt(config);
    35→  return `${base}
    36→## Contenu complet
    37→${additionalContent}
    38→`;
    39→}
    40→
    41→export function validateLlmsTxt(content: string): { valid: boolean; errors: string[] } {
    42→  const errors: string[] = [];
    43→  const required = ['name:', 'url:', 'description:', 'email:', 'allow_training:', 'allow_citation:'];
    44→
    45→  required.forEach((key) => {
    46→    if (!content.includes(key)) {
    47→      errors.push(`Champ manquant: ${key}`);
    48→    }
    49→  });
    50→
    51→  return { valid: errors.length === 0, errors };
    52→}
