     1→import { Recommendation, GeneratedSolution } from '../types';
     2→import { sanitizePromptText, normalizeUrl, isValidUrl, safeHostname } from '../utils/validation';
     3→
     4→const buildFallbackSolution = (rec: Recommendation, url: string): GeneratedSolution => {
     5→  const safeDomain = safeHostname(url) || 'exemple.com';
     6→  return {
     7→    title: `Optimisation : ${rec.title}`,
     8→    explanation: "Cette solution structure vos données pour faciliter l'extraction d'entités par les LLMs.",
     9→    type: 'code',
    10→    language: 'html',
    11→    content: `<!-- Script AEO automatique (Fallback) -->\n<script type="application/ld+json">\n{\n  "@context": "https://schema.org",\n  "@type": "WebPage",\n  "mainEntity": {\n    "@type": "Organization",\n    "name": "${safeDomain}"\n  }\n}\n</script>`,
    12→    implementationSteps: [
    13→      "Ouvrez le fichier template de votre page",
    14→      "Insérez le script dans la balise <head>",
    15→      "Validez avec l'outil d'inspection de schémas"
    16→    ]
    17→  };
    18→};
    19→
    20→export const generateSolution = async (rec: Recommendation, url: string): Promise<GeneratedSolution> => {
    21→  const normalizedUrl = normalizeUrl(url);
    22→  if (!isValidUrl(normalizedUrl)) {
    23→    throw new Error("URL invalide pour la génération.");
    24→  }
    25→
    26→  const safeRec: Recommendation = {
    27→    ...rec,
    28→    title: sanitizePromptText(rec.title),
    29→    description: sanitizePromptText(rec.description),
    30→    action: sanitizePromptText(rec.action),
    31→    category: sanitizePromptText(rec.category)
    32→  };
    33→
    34→  try {
    35→    const response = await fetch('/api/generate-solution', {
    36→      method: 'POST',
    37→      headers: { 'Content-Type': 'application/json' },
    38→      body: JSON.stringify({
    39→        rec: safeRec,
    40→        url: normalizedUrl
    41→      })
    42→    });
    43→
    44→    if (!response.ok) {
    45→      const errorPayload = await response.json().catch(() => null);
    46→      const detail = errorPayload?.error || `Erreur serveur (${response.status}).`;
    47→      throw new Error(detail);
    48→    }
    49→
    50→    const data = await response.json();
    51→    return data as GeneratedSolution;
    52→  } catch (e) {
    53→    console.error("Erreur Gemini Generator:", e);
    54→    return buildFallbackSolution(rec, normalizedUrl);
    55→  }
    56→};
