     2→
     3→interface Props {
     4→  children: React.ReactNode;
     5→}
     6→
     7→interface State {
     8→  hasError: boolean;
     9→}
    10→
    11→class ErrorBoundary extends Component<Props, State> {
    12→  declare props: Props;
    13→  state: State = { hasError: false };
    14→
    15→  static getDerivedStateFromError(): State {
    16→    return { hasError: true };
    17→  }
    18→
    19→  componentDidCatch(error: Error, info: React.ErrorInfo) {
    20→    console.error('Erreur capturée par ErrorBoundary:', error, info);
    21→  }
    22→
    23→  handleReload = () => {
    24→    window.location.reload();
    25→  };
    26→
    27→  render() {
    28→    if (this.state.hasError) {
    29→      return (
    30→        <div className="min-h-[60vh] flex items-center justify-center px-6">
    31→          <div className="max-w-lg w-full glass-panel p-8 rounded-2xl border border-white/10 text-center">
    32→            <h2 className="text-2xl font-serif font-bold text-white mb-3">Oups, une erreur est survenue</h2>
    33→            <p className="text-sm text-gray-400 mb-6">Une erreur inattendue a été capturée. Vous pouvez recharger la page.</p>
    34→            <button onClick={this.handleReload} className="px-4 py-2 bg-primary text-black font-bold rounded-lg hover:bg-emerald-400 transition-all">
    35→              Recharger
    36→            </button>
    37→          </div>
    38→        </div>
    39→      );
    40→    }
    41→
    42→    return this.props.children;
    43→  }
    44→}
    45→
    46→export default ErrorBoundary;
    47→

