     1→import { NextResponse } from 'next/server';
     2→import { isValidUrl, normalizeUrl } from '../../../utils/validation';
     3→
     4→const MAX_CHARS = 200000;
     5→
     6→export async function GET(request: Request) {
     7→  const { searchParams } = new URL(request.url);
     8→  const rawUrl = searchParams.get('url') || '';
     9→  const normalized = normalizeUrl(rawUrl);
    10→
    11→  if (!isValidUrl(normalized)) {
    12→    return NextResponse.json({ error: 'URL invalide.' }, { status: 400 });
    13→  }
    14→
    15→  try {
    16→    const response = await fetch(normalized, {
    17→      method: 'GET',
    18→      headers: {
    19→        'User-Agent': 'CitedBy.ai Fetcher/1.0'
    20→      }
    21→    });
    22→
    23→    if (!response.ok) {
    24→      return NextResponse.json({ error: 'Echec de recuperation.' }, { status: response.status });
    25→    }
    26→
    27→    const text = await response.text();
    28→    const truncated = text.slice(0, MAX_CHARS);
    29→    return new NextResponse(truncated, {
    30→      status: 200,
    31→      headers: { 'Content-Type': 'text/plain; charset=utf-8' }
    32→    });
    33→  } catch {
    34→    return NextResponse.json({ error: 'Erreur reseau.' }, { status: 500 });
    35→  }
    36→}
